            "soru", "sorum", "sorabilir", "miyim", "biliyor", "musunuz", "uygun",
            "katilmak", "katılmak", "ariyorum", "arıyorum", "bul", "bulabilir", "yapar",
            "ise", "idi", "imis", "imiş", "dır", "dir", "dur", "dür", "tır", "tir", "tur", "tür",
